/**
 * @brief lookup a futex hash node
 *
 * @param table hash table
 * @param key key
 * @param release whether release lock
 * @param holding whether holding lock
 * @return void* futex (NOTE: not futex_hash_node) if success, NULL if failed
 */
static void *__futex_hash_lookup(struct hash_table *table, void *key, int release, int holding) {
    uint64 uaddr = (uint64) key;
    struct hash_entry *entry = hash_get_entry(table, key, holding);
    if (entry == NULL) {
        if (release) {
            release(&table->lock);
        }
        return NULL;
    }

    struct futex_hash_node *pos, *n;
    list_for_each_entry_safe(pos, n, &entry->list, futex_hash_list_node) {
        if (pos->uaddr == uaddr) {
            if (release) {
                release(&table->lock);
            }
            return pos->fp;
        }
    }

    if (release) {
        release(&table->lock);
    }
    return NULL;
}

